ss","../node_modules/bootstrap/scss/_list-group.scss","../node_modules/bootstrap/scss/_close.scss","../node_modules/bootstrap/scss/_toasts.scss","../node_modules/bootstrap/scss/_modal.scss","../node_modules/bootstrap/scss/mixins/_backdrop.scss","../node_modules/bootstrap/scss/_tooltip.scss","../node_modules/bootstrap/scss/mixins/_reset-text.scss","../node_modules/bootstrap/scss/_popover.scss","../node_modules/bootstrap/scss/_carousel.scss","../node_modules/bootstrap/scss/_spinners.scss","../node_modules/bootstrap/scss/_offcanvas.scss","../node_modules/bootstrap/scss/_placeholders.scss","../node_modules/bootstrap/scss/mixins/_clearfix.scss","../node_modules/bootstrap/scss/helpers/_color-bg.scss","../node_modules/bootstrap/scss/helpers/_colored-links.scss","../node_modules/bootstrap/scss/helpers/_focus-ring.scss","../node_modules/bootstrap/scss/helpers/_icon-link.scss","../node_modules/bootstrap/scss/helpers/_ratio.scss","../node_modules/bootstrap/scss/helpers/_position.scss","../node_modules/bootstrap/scss/helpers/_stacks.scss","../node_modules/bootstrap/scss/helpers/_visually-hidden.scss","../node_modules/bootstrap/scss/mixins/_visually-hidden.scss","../node_modules/bootstrap/scss/helpers/_stretched-link.scss","../node_modules/bootstrap/scss/helpers/_text-truncation.scss","../node_modules/bootstrap/scss/mixins/_text-truncate.scss","../node_modules/bootstrap/scss/helpers/_vr.scss","../node_modules/bootstrap/scss/mixins/_utilities.scss","../node_modules/bootstrap/scss/utilities/_api.scss"],"sourcesContent":["//\n// Headings\n//\n.h1 {\n  @extend h1;\n}\n\n.h2 {\n  @extend h2;\n}\n\n.h3 {\n  @extend h3;\n}\n\n.h4 {\n  @extend h4;\n}\n\n.h5 {\n  @extend h5;\n}\n\n.h6 {\n  @extend h6;\n}\n\n\n.lead {\n  @include font-size($lead-font-size);\n  font-weight: $lead-font-weight;\n}\n\n// Type display classes\n@each $display, $font-size in $display-font-sizes {\n  .display-#{$display} {\n    @include font-size($font-size);\n    font-family: $display-font-family;\n    font-style: $display-font-style;\n    font-weight: $display-font-weight;\n    line-height: $display-line-height;\n  }\n}\n\n//\n// Emphasis\n//\n.small {\n  @extend small;\n}\n\n.mark {\n  @extend mark;\n}\n\n//\n// Lists\n//\n\n.list-unstyled {\n  @include list-unstyled();\n}\n\n// Inline turns list items into inline-block\n.list-inline {\n  @include list-unstyled();\n}\n.list-inline-item {\n  display: inline-block;\n\n  &:not(:last-child) {\n    margin-right: $list-inline-padding;\n  }\n}\n\n\n//\n// Misc\n//\n\n// Builds on `abbr`\n.initialism {\n  @include font-size($initialism-font-size);\n  text-transform: uppercase;\n}\n\n// Blockquotes\n.blockquote {\n  margin-bottom: $blockquote-margin-y;\n  @include font-size($blockquote-font-size);\n\n  > :last-child {\n    margin-bottom: 0;\n  }\n}\n\n.blockquote-footer {\n  margin-top: -$blockquote-margin-y;\n  margin-bottom: $blockquote-margin-y;\n  @include font-size($blockquote-footer-font-size);\n  color: $blockquote-footer-color;\n\n  &::before {\n    content: \"\\2014\\00A0\"; // em dash, nbsp\n  }\n}\n","// Responsive images (ensure images don't scale beyond their parents)\n//\n// This is purposefully opt-in via an explicit class rather than being the default for all `<img>`s.\n// We previously tried the \"images are responsive by default\" approach in Bootstrap v2,\n// and abandoned it in Bootstrap v3 because it breaks lots of third-party widgets (including Google Maps)\n// which weren't expecting the images within themselves to be involuntarily resized.\n// See also https://github.com/twbs/bootstrap/issues/18178\n.img-fluid {\n  @include img-fluid();\n}\n\n\n// Image thumbnails\n.img-thumbnail {\n  padding: $thumbnail-padding;\n  background-color: $thumbnail-bg;\n  border: $thumbnail-border-width solid $thumbnail-border-color;\n  @include border-radius($thumbnail-border-radius);\n  @include box-shadow($thumbnail-box-shadow);\n\n  // Keep them at most 100% wide\n  @include img-fluid();\n}\n\n//\n// Figures\n//\n\n.figure {\n  // Ensures the caption's text aligns with the image.\n  display: inline-block;\n}\n\n.figure-img {\n  margin-bottom: $spacer * .5;\n  line-height: 1;\n}\n\n.figure-caption {\n  @include font-size($figure-caption-font-size);\n  color: $figure-caption-color;\n}\n","@import url(\"https://fonts.googleapis.com/css2?family=Raleway:wght@500&display=swap\");\r\nbody {\r\n  margin: 0;\r\n  font-family: \"Raleway\", serif !important;\r\n  -webkit-font-smoothing: antialiased;\r\n  -moz-osx-font-smoothing: grayscale;\r\n  background-image: linear-gradient(to left, rgb(27 20 41), rgb(20 15 35));\r\n}\r\n","/* Copyright 2014 Mozilla Foundation\n *\n * Licensed under the Apache License, Version 2.0 (the \"License\");\n * you may not use this file except in compliance with the License.\n * You may obtain a copy of the License at\n *\n *     http://www.apache.org/licenses/LICENSE-2.0\n *\n * Unless required by applicable law or agreed to in writing, software\n * distributed under the License is distributed on an \"AS IS\" BASIS,\n * WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n * See the License for the specific language governing permissions and\n * limitations under the License.\n */\n\n:root {\n  --annotation-unfocused-field-background: url(\"data:image/svg+xml;charset=UTF-8,<svg width='1px' height='1px' xmlns='http://www.w3.org/2000/svg'><rect width='100%' height='100%' style='fill:rgba(0, 54, 255, 0.13);'/></svg>\");\n}\n\n.annotationLayer section {\n  position: absolute;\n  text-align: initial;\n}\n\n.annotationLayer .linkAnnotation > a,\n.annotationLayer .buttonWidgetAnnotation.pushButton > a {\n  position: absolute;\n  font-size: 1em;\n  top: 0;\n  left: 0;\n  width: 100%;\n  height: 100%;\n}\n\n.annotationLayer .buttonWidgetAnnotation.pushButton > canvas {\n  position: relative;\n  top: 0;\n  left: 0;\n  z-index: -1;\n}\n\n.annotationLayer .linkAnnotation > a:hover,\n.annotationLayer .buttonWidgetAnnotation.pushButton > a:hover {\n  opacity: 0.2;\n  background: rgba(255, 255, 0, 1);\n  box-shadow: 0 2px 10px rgba(255, 255, 0, 1);\n}\n\n.annotationLayer .textAnnotation img {\n  position: absolute;\n  cursor: pointer;\n}\n\n.annotationLayer .textWidgetAnnotation input,\n.annotationLayer .textWidgetAnnotation textarea,\n.annotationLayer .choiceWidgetAnnotation select,\n.annotationLayer .buttonWidgetAnnotation.checkBox input,\n.annotationLayer .buttonWidgetAnnotation.radioButton input {\n  background-image: var(--annotation-unfocused-field-background);\n  border: 1px solid transparent;\n  box-sizing: border-box;\n  font-size: 9px;\n  height: 100%;\n  margin: 0;\n  padding: 0 3px;\n  vertical-align: top;\n  width: 100%;\n}\n\n.annotationLayer .choiceWidgetAnnotation select option {\n  padding: 0;\n}\n\n.annotationLayer .buttonWidgetAnnotation.radioButton input {\n  border-radius: 50%;\n}\n\n.annotationLayer .textWidgetAnnotation textarea {\n  font: message-box;\n  font-size: 9px;\n  resize: none;\n}\n\n.annotationLayer .textWidgetAnnotation input[disabled],\n.annotationLayer .textWidgetAnnotation textarea[disabled],\n.annotationLayer .choiceWidgetAnnotation select[disabled],\n.annotationLayer .buttonWidgetAnnotation.checkBox input[disabled],\n.annotationLayer .buttonWidgetAnnotation.radioButton input[disabled] {\n  background: none;\n  border: 1px solid transparent;\n  cursor: not-allowed;\n}\n\n.annotationLayer .textWidgetAnnotation input:hover,\n.annotationLayer .textWidgetAnnotation textarea:hover,\n.annotationLayer .choiceWidgetAnnotation select:hover,\n.annotationLayer .buttonWidgetAnnotation.checkBox input:hover,\n.annotationLayer .buttonWidgetAnnotation.radioButton input:hover {\n  border: 1px solid rgba(0, 0, 0, 1);\n}\n\n.annotationLayer .textWidgetAnnotation input:focus,\n.annotationLayer .textWidgetAnnotation textarea:focus,\n.annotationLayer .choiceWidgetAnnotation select:focus {\n  background: none;\n  border: 1px solid transparent;\n}\n\n.annotationLayer .textWidgetAnnotation input :focus,\n.annotationLayer .textWidgetAnnotation textarea :focus,\n.annotationLayer .choiceWidgetAnnotation select :focus,\n.annotationLayer .buttonWidgetAnnotation.checkBox :focus,\n.annotationLayer .buttonWidgetAnnotation.radioButton :focus {\n  background-image: none;\n  background-color: transparent;\n  outline: auto;\n}\n\n.annotationLayer .buttonWidgetAnnotation.checkBox input:checked:before,\n.annotationLayer .buttonWidgetAnnotation.checkBox input:checked:after,\n.annotationLayer .buttonWidgetAnnotation.radioButton input:checked:before {\n  background-color: rgba(0, 0, 0, 1);\n  content: '';\n  display: block;\n  position: absolute;\n}\n\n.annotationLayer .buttonWidgetAnnotation.checkBox input:checked:before,\n.annotationLayer .buttonWidgetAnnotation.checkBox input:checked:after {\n  height: 80%;\n  left: 45%;\n  width: 1px;\n}\n\n.annotationLayer .buttonWidgetAnnotation.checkBox input:checked:before {\n  transform: rotate(45deg);\n}\n\n.annotationLayer .buttonWidgetAnnotation.checkBox input:checked:after {\n  transform: rotate(-45deg);\n}\n\n.annotationLayer .buttonWidgetAnnotation.radioButton input:checked:before {\n  border-radius: 50%;\n  height: 50%;\n  left: 30%;\n  top: 20%;\n  width: 50%;\n}\n\n.annotationLayer .textWidgetAnnotation input.comb {\n  font-family: monospace;\n  padding-left: 2px;\n  padding-right: 0;\n}\n\n.annotationLayer .textWidgetAnnotation input.comb:focus {\n  /*\n   * Letter spacing is placed on the right side of each character. Hence, the\n   * letter spacing of the last character may be placed outside the visible\n   * area, causing horizontal scrolling. We avoid this by extending the width\n   * when the element has focus and revert this when it loses focus.\n   */\n  width: 103%;\n}\n\n.annotationLayer .buttonWidgetAnnotation.checkBox input,\n.annotationLayer .buttonWidgetAnnotation.radioButton input {\n  appearance: none;\n  padding: 0;\n}\n\n.annotationLayer .popupWrapper {\n  position: absolute;\n  width: 20em;\n}\n\n.annotationLayer .popup {\n  position: absolute;\n  z-index: 200;\n  max-width: 20em;\n  background-color: rgba(255, 255, 153, 1);\n  box-shadow: 0 2px 5px rgba(136, 136, 136, 1);\n  border-radius: 2px;\n  padding: 6px;\n  margin-left: 5px;\n  cursor: pointer;\n  font: message-box;\n  font-size: 9px;\n  white-space: normal;\n  word-wrap: break-word;\n}\n\n.annotationLayer .popup > * {\n  font-size: 9px;\n}\n\n.annotationLayer .popup h1 {\n  display: inline-block;\n}\n\n.annotationLayer .popupDate {\n  display: inline-block;\n  margin-left: 5px;\n}\n\n.annotationLayer .popupContent {\n  border-top: 1px solid rgba(51, 51, 51, 1);\n  margin-top: 2px;\n  padding-top: 2px;\n}\n\n.annotationLayer .richText > * {\n  white-space: pre-wrap;\n}\n\n.annotationLayer .highlightAnnotation,\n.annotationLayer .underlineAnnotation,\n.annotationLayer .squigglyAnnotation,\n.annotationLayer .strikeoutAnnotation,\n.annotationLayer .freeTextAnnotation,\n.annotationLayer .lineAnnotation svg line,\n.annotationLayer .squareAnnotation svg rect,\n.annotationLayer .circleAnnotation svg ellipse,\n.annotationLayer .polylineAnnotation svg polyline,\n.annotationLayer .polygonAnnotation svg polygon,\n.annotationLayer .caretAnnotation,\n.annotationLayer .inkAnnotation svg polyline,\n.annotationLayer .stampAnnotation,\n.annotationLayer .fileAttachmentAnnotation {\n  cursor: pointer;\n}\n","/* ============================\n   CSS Variables & Root\n   ============================ */\nhtml {\n  --section-background-color: linear-gradient(\n    to bottom left,\n    rgba(17, 16, 16, 0.582),\n    rgba(12, 8, 24, 0.904)\n  );\n  --image-gradient: linear-gradient(\n    to bottom left,\n    rgba(17, 16, 16, 0.678),\n    rgba(12, 10, 22, 0.863)\n  );\n  --imp-text-color: #c770f0;\n  --cyan: #00d4ff;\n  --pink: #ff006e;\n  --green: #39ff14;\n  --gold: #ffbe0b;\n  --card-bg: linear-gradient(145deg, rgba(25, 18, 40, 0.95) 0%, rgba(45, 28, 65, 0.9) 100%);\n  --transition-smooth: cubic-bezier(0.175, 0.885, 0.32, 1.275);\n}\n\n.purple { color: var(--imp-text-color) !important; }\n\nbutton:focus { box-shadow: none !important; }\n\n/* ============================\n   Global body\n   ============================ */\nbody {\n  cursor: none;\n}\n\n@media (pointer: coarse) {\n  body { cursor: auto; }\n}\n\n/* ============================\n   Custom Cursor\n   ============================ */\n.custom-cursor {\n  width: 10px;\n  height: 10px;\n  background: var(--imp-text-color);\n  border-radius: 50%;\n  position: fixed;\n  pointer-events: none;\n  z-index: 999999;\n  transform: translate(-50%, -50%);\n  transition: width 0.2s ease, height 0.2s ease, background 0.2s ease;\n  box-shadow: 0 0 8px var(--imp-text-color), 0 0 20px var(--imp-text-color);\n  mix-blend-mode: screen;\n}\n\n.cursor-follower {\n  width: 32px;\n  height: 32px;\n  border: 1.5px solid rgba(199, 112, 240, 0.55);\n  border-radius: 50%;\n  position: fixed;\n  pointer-events: none;\n  z-index: 999998;\n  transform: translate(-50%, -50%);\n  transition: width 0.25s ease, height 0.25s ease, border-color 0.25s ease;\n}\n\n.custom-cursor.cursor-hover {\n  width: 18px;\n  height: 18px;\n  background: var(--cyan);\n  box-shadow: 0 0 12px var(--cyan), 0 0 30px var(--cyan);\n}\n\n.cursor-follower.follower-hover {\n  width: 52px;\n  height: 52px;\n  border-color: rgba(0, 212, 255, 0.55);\n}\n\n@media (pointer: coarse) {\n  .custom-cursor,\n  .cursor-follower { display: none; }\n}\n\n/* ============================\n   Scroll Progress Bar\n   ============================ */\n.scroll-progress-container {\n  position: fixed;\n  top: 0;\n  left: 0;\n  width: 100%;\n  height: 3px;\n  z-index: 100000;\n  background: rgba(199, 112, 240, 0.08);\n}\n\n.scroll-progress-bar {\n  height: 100%;\n  background: linear-gradient(90deg, #c770f0, #00d4ff, #ff006e, #c770f0);\n  background-size: 300% 100%;\n  animation: progressShift 3s linear infinite;\n  box-shadow: 0 0 10px rgba(199, 112, 240, 0.7), 0 0 20px rgba(0, 212, 255, 0.4);\n  transition: width 0.08s linear;\n}\n\n@keyframes progressShift {\n  0%   { background-position: 0% 50%; }\n  100% { background-position: 300% 50%; }\n}\n\n/* ============================\n   Preloader\n   ============================ */\n#preloader {\n  position: fixed;\n  top: 0;\n  left: 0;\n  width: 100%;\n  height: 100%;\n  z-index: 999999;\n  background-color: #0c0513;\n  background-image: url(./Assets/pre.svg);\n  background-repeat: no-repeat;\n  background-position: center;\n}\n\n#preloader-none { opacity: 0; }\n#no-scroll { overflow: hidden; height: 100vh; }\n\n/* ============================\n   Scrollbar\n   ============================ */\n::-webkit-scrollbar { width: 6px; }\n::-webkit-scrollbar-track { background: #1a0d2e; }\n::-webkit-scrollbar-thumb {\n  background: linear-gradient(to bottom, #c770f0, #6e48aa);\n  border-radius: 12px;\n}\n::-webkit-scrollbar-thumb:hover {\n  background: linear-gradient(to bottom, #de82eb, #c770f0);\n}\n\n/* ============================\n   Navbar\n   ============================ */\n.sticky {\n  background-color: rgba(10, 5, 25, 0.88) !important;\n  transition: all 0.3s ease-out !important;\n  box-shadow: 0 4px 30px rgba(199, 112, 240, 0.12) !important;\n  backdrop-filter: blur(18px) !important;\n  -webkit-backdrop-filter: blur(18px) !important;\n  border-bottom: 1px solid rgba(199, 112, 240, 0.1) !important;\n}\n\n.navbar {\n  position: fixed !important;\n  transition: all 0.3s ease-out !important;\n  padding: 0.3rem 2rem !important;\n  font-size: 1.2rem !important;\n}\n\n.navbar-toggler {\n  position: relative !important;\n  background-color: transparent !important;\n  border-color: transparent !important;\n}\n\n.navbar-toggler span {\n  display: block !important;\n  background-color: #be50f4 !important;\n  height: 4px !important;\n  width: 27px !important;\n  margin-top: 5px !important;\n  margin-bottom: 5px !important;\n  transform: rotate(0deg) !important;\n  opacity: 1 !important;\n}\n\n.navbar-toggler:focus,\n.navbar-toggler:active { outline: 0 !important; }\n\n.navbar-toggler span:nth-child(1),\n.navbar-toggler span:nth-child(3) {\n  transition: transform 0.35s ease-in-out !important;\n}\n\n.navbar-toggler:not(.collapsed) span:nth-child(1) {\n  position: absolute !important;\n  left: 12px !important;\n  top: 10px !important;\n  transform: rotate(135deg) !important;\n  opacity: 0.9 !important;\n}\n\n.navbar-toggler:not(.collapsed) span:nth-child(2) {\n  height: 12px !important;\n  visibility: hidden !important;\n  background-color: transparent !important;\n}\n\n.navbar-toggler:not(.collapsed) span:nth-child(3) {\n  position: absolute !important;\n  left: 12px !important;\n  top: 10px !important;\n  transform: rotate(-135deg) !important;\n  opacity: 0.9 !important;\n}\n\n@media (max-width: 767px) {\n  .navbar {\n    padding: 1rem 2rem !important;\n    font-size: 1.4rem !important;\n    background-color: rgba(10, 5, 25, 0.95) !important;\n  }\n  .navbar-nav .nav-item a::after { display: none !important; }\n}\n\n.navbar-brand { color: rgb(250, 250, 250) !important; }\n.logo { height: 1.4em !important; width: 2.5em !important; }\n\n.logo-text {\n  font-size: 1.8em !important;\n  font-weight: 800 !important;\n  background: linear-gradient(135deg, #e879f9 0%, #c770f0 50%, #a855f7 100%) !important;\n  -webkit-background-clip: text !important;\n  -webkit-text-fill-color: transparent !important;\n  background-clip: text !important;\n  letter-spacing: 3px !important;\n  font-family: 'Georgia', 'Times New Roman', serif !important;\n  filter: drop-shadow(0 0 8px rgba(199, 112, 240, 0.5)) !important;\n  transition: all 0.3s ease !important;\n  padding: 5px 12px !important;\n  border: 2px solid rgba(199, 112, 240, 0.5) !important;\n  border-radius: 10px !important;\n}\n\n.logo-text:hover {\n  filter: drop-shadow(0 0 18px rgba(199, 112, 240, 0.9)) !important;\n  border-color: rgba(199, 112, 240, 0.9) !important;\n  transform: scale(1.06) !important;\n}\n\n.navbar-nav .nav-link {\n  color: white !important;\n  padding-right: 1rem !important;\n  padding-left: 1rem !important;\n}\n\n.nav-link { padding: 0.8rem 1rem !important; }\n\n@media (max-width: 767px) {\n  .nav-link { padding: 0.7rem 1rem !important; }\n}\n\n.navbar-nav .nav-item {\n  position: relative;\n  margin-left: 20px;\n}\n\n.navbar-nav .nav-item a {\n  font-weight: 400;\n  transition: all 0.3s ease-out;\n  position: relative;\n  z-index: 1;\n}\n\n.navbar-nav .nav-item a::after {\n  content: \"\";\n  position: relative;\n  display: block;\n  height: 3px;\n  width: 0;\n  border-radius: 16px;\n  background: linear-gradient(90deg, #c770f0, #00d4ff);\n  bottom: 1px;\n  left: 0;\n  z-index: -1;\n  transition: width 0.3s ease-out;\n}\n\n.navbar-nav .nav-item a:hover::after { width: 100%; }\n\n/* ============================\n   Aurora Background\n   ============================ */\n.aurora-bg {\n  position: absolute;\n  inset: 0;\n  overflow: hidden;\n  z-index: 0;\n  pointer-events: none;\n}\n\n.aurora-blob {\n  position: absolute;\n  border-radius: 50%;\n  filter: blur(90px);\n  opacity: 0;\n  animation: auroraFloat ease-in-out infinite;\n}\n\n.aurora-blob-1 {\n  width: 700px;\n  height: 700px;\n  background: radial-gradient(circle, rgba(199, 112, 240, 0.6), transparent 70%);\n  top: -250px;\n  left: -150px;\n  animation-duration: 9s;\n  animation-delay: 0s;\n}\n\n.aurora-blob-2 {\n  width: 500px;\n  height: 500px;\n  background: radial-gradient(circle, rgba(0, 212, 255, 0.5), transparent 70%);\n  top: -100px;\n  right: -120px;\n  animation-duration: 11s;\n  animation-delay: -4s;\n}\n\n.aurora-blob-3 {\n  width: 350px;\n  height: 350px;\n  background: radial-gradient(circle, rgba(255, 0, 110, 0.4), transparent 70%);\n  bottom: 80px;\n  left: 35%;\n  animation-duration: 8s;\n  animation-delay: -6s;\n}\n\n.aurora-blob-4 {\n  width: 250px;\n  height: 250px;\n  background: radial-gradient(circle, rgba(57, 255, 20, 0.25), transparent 70%);\n  bottom: 0;\n  right: 20%;\n  animation-duration: 13s;\n  animation-delay: -2s;\n}\n\n@keyframes auroraFloat {\n  0%, 100% {\n    transform: translate(0, 0) scale(1);\n    opacity: 0.12;\n  }\n  25%  { transform: translate(25px, -20px) scale(1.06); opacity: 0.18; }\n  50%  { transform: translate(-20px, 28px) scale(0.94); opacity: 0.14; }\n  75%  { transform: translate(-28px, -12px) scale(1.04); opacity: 0.16; }\n}\n\n/* ============================\n   Home Section\n   ============================ */\n.wave {\n  animation-name: wave-animation;\n  animation-duration: 2.1s;\n  animation-iteration-count: infinite;\n  transform-origin: 70% 70%;\n  display: inline-block;\n}\n\n@keyframes wave-animation {\n  0%   { transform: rotate(0deg); }\n  10%  { transform: rotate(14deg); }\n  20%  { transform: rotate(-8deg); }\n  30%  { transform: rotate(14deg); }\n  40%  { transform: rotate(-4deg); }\n  50%  { transform: rotate(10deg); }\n  60%  { transform: rotate(0deg); }\n  100% { transform: rotate(0deg); }\n}\n\n#tsparticles {\n  position: fixed !important;\n  background-repeat: no-repeat !important;\n  background-size: cover !important;\n  width: 100%;\n  height: 100%;\n}\n\n.home-header { padding-top: 80px !important; }\n\n.home-section {\n  position: relative;\n  z-index: 0;\n  background-image: var(--image-gradient), url(./Assets/home-bg.jpg);\n  background-position: top center;\n  background-repeat: no-repeat;\n  padding-bottom: 30px !important;\n  padding-top: 30px !important;\n  overflow: hidden;\n  min-height: 100vh;\n}\n\n.home-content {\n  padding: 9rem 0 2rem !important;\n  color: whitesmoke;\n  text-align: left;\n  position: relative;\n  z-index: 2;\n}\n\n.heading {\n  font-size: 2.4em !important;\n  padding-left: 50px !important;\n}\n\n.heading-name {\n  font-size: 2.5em !important;\n  padding-left: 45px !important;\n  line-height: 1.3;\n}\n\n.main-name { color: #cd5ff8; }\n\n/* ============================\n   Glitch Text Effect\n   ============================ */\n.glitch-text {\n  position: relative;\n  color: #cd5ff8;\n  display: inline-block;\n}\n\n.glitch-text::before,\n.glitch-text::after {\n  content: attr(data-text);\n  position: absolute;\n  top: 0;\n  left: 0;\n  width: 100%;\n  height: 100%;\n  pointer-events: none;\n}\n\n.glitch-text::before {\n  color: var(--cyan);\n  animation: glitchTop 4s infinite;\n  clip-path: polygon(0 0, 100% 0, 100% 35%, 0 35%);\n  transform: translate(-3px, 0);\n  opacity: 0;\n}\n\n.glitch-text::after {\n  color: var(--pink);\n  animation: glitchBot 4s infinite;\n  clip-path: polygon(0 65%, 100% 65%, 100% 100%, 0 100%);\n  transform: translate(3px, 0);\n  opacity: 0;\n}\n\n@keyframes glitchTop {\n  0%, 88%, 100% { opacity: 0; transform: translate(0); }\n  90%  { opacity: 1; transform: translate(-4px, 0); }\n  91%  { opacity: 0; }\n  93%  { opacity: 1; transform: translate(4px, 0); }\n  95%  { opacity: 0; }\n}\n\n@keyframes glitchBot {\n  0%, 88%, 100% { opacity: 0; transform: translate(0); }\n  91%  { opacity: 1; transform: translate(4px, 0); }\n  92%  { opacity: 0; }\n  94%  { opacity: 1; transform: translate(-4px, 0); }\n  96%  { opacity: 0; }\n}\n\n/* ============================\n   Neon text glow\n   ============================ */\n.neon-text {\n  text-shadow:\n    0 0 7px var(--imp-text-color),\n    0 0 14px var(--imp-text-color),\n    0 0 30px rgba(199, 112, 240, 0.5);\n  animation: neonPulse 3s ease-in-out infinite alternate;\n}\n\n@keyframes neonPulse {\n  from {\n    text-shadow:\n      0 0 5px var(--imp-text-color),\n      0 0 10px var(--imp-text-color),\n      0 0 20px rgba(199, 112, 240, 0.4);\n  }\n  to {\n    text-shadow:\n      0 0 10px var(--imp-text-color),\n      0 0 25px var(--imp-text-color),\n      0 0 50px rgba(199, 112, 240, 0.6),\n      0 0 80px rgba(199, 112, 240, 0.3);\n  }\n}\n\n/* ============================\n   Avatar\n   ============================ */\n.home-avatar-col {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  padding-bottom: 60px;\n  padding-top: 40px;\n}\n\n.avatar-wrapper {\n  position: relative;\n  display: inline-block;\n}\n\n.home-avatar-img {\n  width: min(100%, 420px);\n  max-height: 520px;\n  height: auto;\n  object-fit: contain;\n  display: block;\n  border-radius: 20px;\n  position: relative;\n  z-index: 2;\n  filter: drop-shadow(0 0 20px rgba(199, 112, 240, 0.35));\n  transition: filter 0.4s ease;\n}\n\n.home-avatar-img:hover {\n  filter: drop-shadow(0 0 40px rgba(199, 112, 240, 0.7));\n}\n\n.avatar-ring {\n  position: absolute;\n  inset: -12px;\n  border-radius: 28px;\n  background: linear-gradient(135deg, #c770f0, #00d4ff, #ff006e, #c770f0);\n  background-size: 300% 300%;\n  animation: ringRotate 5s linear infinite;\n  z-index: 1;\n  opacity: 0.7;\n  padding: 3px;\n  -webkit-mask:\n    linear-gradient(#fff 0 0) content-box,\n    linear-gradient(#fff 0 0);\n  -webkit-mask-composite: xor;\n  mask-composite: exclude;\n}\n\n@keyframes ringRotate {\n  0%   { background-position: 0% 50%; }\n  100% { background-position: 300% 50%; }\n}\n\n.avatar-glow {\n  position: absolute;\n  inset: -30px;\n  border-radius: 50%;\n  background: radial-gradient(circle, rgba(199, 112, 240, 0.2), transparent 70%);\n  z-index: 0;\n  animation: glowBreath 4s ease-in-out infinite alternate;\n  pointer-events: none;\n}\n\n@keyframes glowBreath {\n  from { opacity: 0.5; transform: scale(0.95); }\n  to   { opacity: 1;   transform: scale(1.05); }\n}\n\n@media (max-width: 767px) {\n  .home-avatar-col { padding-top: 20px; padding-bottom: 20px; }\n  .home-avatar-img { max-height: 280px; }\n}\n\n/* ============================\n   Typewriter\n   ============================ */\n.Typewriter__wrapper {\n  font-size: 2.2em !important;\n  color: #be6adf !important;\n  font-weight: 600 !important;\n}\n\n.Typewriter__cursor {\n  font-size: 2.4em !important;\n  color: #b562d6 !important;\n}\n\n@media (max-width: 767px) {\n  .Typewriter__wrapper {\n    font-size: 1.4em !important;\n    font-weight: 500 !important;\n    position: absolute !important;\n  }\n  .Typewriter__cursor { display: none !important; }\n}\n\n/* ============================\n   Stats Counter\n   ============================ */\n.stats-section {\n  padding: 40px 0 20px;\n  position: relative;\n  z-index: 2;\n}\n\n.stat-item {\n  text-align: center;\n  padding: 16px 8px;\n  position: relative;\n}\n\n.stat-item::after {\n  content: \"\";\n  position: absolute;\n  right: 0;\n  top: 20%;\n  height: 60%;\n  width: 1px;\n  background: rgba(199, 112, 240, 0.2);\n}\n\n.stat-item:last-child::after { display: none; }\n\n.stat-emoji {\n  display: block;\n  font-size: 1.8em;\n  margin-bottom: 6px;\n  animation: emojiFloat 3s ease-in-out infinite;\n}\n\n.stat-item:nth-child(2) .stat-emoji { animation-delay: -0.8s; }\n.stat-item:nth-child(3) .stat-emoji { animation-delay: -1.6s; }\n.stat-item:nth-child(4) .stat-emoji { animation-delay: -2.4s; }\n\n@keyframes emojiFloat {\n  0%, 100% { transform: translateY(0); }\n  50%       { transform: translateY(-5px); }\n}\n\n.stat-number {\n  display: block;\n  font-size: 3em;\n  font-weight: 800;\n  background: linear-gradient(135deg, #c770f0 0%, #00d4ff 100%);\n  -webkit-background-clip: text;\n  -webkit-text-fill-color: transparent;\n  background-clip: text;\n  line-height: 1;\n}\n\n.stat-label {\n  display: block;\n  font-size: 0.78em;\n  color: rgba(255, 255, 255, 0.55);\n  text-transform: uppercase;\n  letter-spacing: 2px;\n  margin-top: 6px;\n}\n\n@media (max-width: 767px) {\n  .stat-number { font-size: 2.2em; }\n  .stat-label  { font-size: 0.68em; letter-spacing: 1px; }\n  .stat-item::after { display: none; }\n}\n\n/* ============================\n   Home About Section\n   ============================ */\n.myAvtar {\n  justify-content: center !important;\n  padding-top: 9em !important;\n}\n\n@media (max-width: 767px) {\n  .myAvtar { padding-top: 2em !important; padding-bottom: 2em !important; }\n}\n\n.home-about-section {\n  position: relative;\n  padding-bottom: 70px !important;\n  padding-top: 70px !important;\n}\n\n.home-about-description {\n  color: white !important;\n  padding-top: 100px !important;\n  padding-bottom: 20px !important;\n  text-align: center;\n}\n\n.home-about-body {\n  padding-top: 50px;\n  font-size: 1.2em !important;\n  text-align: left;\n}\n\n.nav-guide-list {\n  padding-left: 18px;\n}\n\n.nav-link-word {\n  position: relative;\n  padding-bottom: 1px;\n}\n\n.nav-link-word::after {\n  content: \"\";\n  position: absolute;\n  bottom: 0;\n  left: 0;\n  width: 0;\n  height: 2px;\n  background: linear-gradient(90deg, #c770f0, #00d4ff);\n  transition: width 0.3s ease;\n}\n\n.nav-link-word:hover::after { width: 100%; }\n\n.contact-img-wrapper {\n  position: relative;\n  border-radius: 16px;\n  overflow: hidden;\n}\n\n.contact-img-wrapper img {\n  border-radius: 16px;\n  transition: transform 0.4s ease;\n}\n\n.contact-img-wrapper:hover img { transform: scale(1.03); }\n\n.contact-img-glow {\n  position: absolute;\n  inset: 0;\n  border-radius: 16px;\n  background: linear-gradient(135deg, rgba(199, 112, 240, 0.12), rgba(0, 212, 255, 0.08));\n  pointer-events: none;\n}\n\n.home-about-social {\n  text-align: center !important;\n  padding-top: 25px;\n  color: white !important;\n}\n\n.home-about-social-links {\n  justify-content: center !important;\n  padding-top: 15px !important;\n  display: inline-block !important;\n  position: relative !important;\n  padding-inline-start: 0 !important;\n}\n\n.home-social-icons {\n  position: relative !important;\n  display: inline-flex !important;\n  align-items: center !important;\n  justify-content: center !important;\n  width: 55px !important;\n  height: 55px !important;\n  font-size: 1.5em !important;\n  background: rgba(255, 255, 255, 0.06) !important;\n  border: 1.5px solid rgba(199, 112, 240, 0.35) !important;\n  border-radius: 50% !important;\n  transition: all 0.35s var(--transition-smooth) !important;\n  color: white !important;\n}\n\n.home-social-icons:hover {\n  color: white !important;\n  background: var(--social-color, var(--imp-text-color)) !important;\n  border-color: var(--social-color, var(--imp-text-color)) !important;\n  transform: translateY(-6px) scale(1.12) !important;\n  box-shadow: 0 8px 30px color-mix(in srgb, var(--social-color, #c770f0) 60%, transparent) !important;\n}\n\n.social-icons {\n  display: inline-block !important;\n  padding-right: 15px;\n  padding-left: 15px;\n}\n\n.icon-colour { color: white !important; }\n\n.home-about-social h1 {\n  font-size: 2em !important;\n  margin-bottom: 10px !important;\n  background: linear-gradient(135deg, #c770f0 0%, #00d4ff 50%, #ff006e 100%);\n  -webkit-background-clip: text;\n  -webkit-text-fill-color: transparent;\n  background-clip: text;\n  background-size: 200% 100%;\n  animation: gradientShift 4s ease infinite;\n}\n\n@keyframes gradientShift {\n  0%, 100% { background-position: 0% 50%; }\n  50%       { background-position: 100% 50%; }\n}\n\n/* ============================\n   Scroll Reveal Animations\n   ============================ */\n.reveal {\n  opacity: 0;\n  transform: translateY(35px);\n  transition: opacity 0.65s ease, transform 0.65s ease;\n}\n\n.reveal-left {\n  opacity: 0;\n  transform: translateX(-35px);\n  transition: opacity 0.65s ease, transform 0.65s ease;\n}\n\n.reveal-right {\n  opacity: 0;\n  transform: translateX(35px);\n  transition: opacity 0.65s ease, transform 0.65s ease;\n}\n\n.reveal-scale {\n  opacity: 0;\n  transform: scale(0.85);\n  transition: opacity 0.6s ease, transform 0.6s ease;\n}\n\n.reveal.revealed,\n.reveal-left.revealed,\n.reveal-right.revealed,\n.reveal-scale.revealed {\n  opacity: 1;\n  transform: none;\n}\n\n/* ============================\n   3D Flip Cards — Projects\n   ============================ */\n.flip-card {\n  perspective: 1200px;\n  min-height: 420px;\n  height: 100%;\n}\n\n.flip-card-inner {\n  position: relative;\n  width: 100%;\n  height: 100%;\n  min-height: 420px;\n  transition: transform 0.7s cubic-bezier(0.4, 0.2, 0.2, 1);\n  transform-style: preserve-3d;\n}\n\n.flip-card:hover .flip-card-inner,\n.flip-card.is-flipped .flip-card-inner {\n  transform: rotateY(180deg);\n}\n\n.flip-card-front,\n.flip-card-back {\n  position: absolute;\n  width: 100%;\n  height: 100%;\n  backface-visibility: hidden;\n  -webkit-backface-visibility: hidden;\n  border-radius: 18px;\n  overflow: hidden;\n}\n\n.flip-card-front {\n  background: var(--card-bg);\n  border: 1px solid rgba(200, 137, 230, 0.2);\n  box-shadow: 0 6px 20px rgba(119, 53, 136, 0.35);\n  display: block;\n}\n\n.flip-card-img {\n  width: 100%;\n  height: 100%;\n  object-fit: cover;\n  border-radius: 18px;\n  opacity: 0.92;\n  transition: opacity 0.3s ease;\n}\n\n.flip-card:hover .flip-card-img { opacity: 1; }\n\n.flip-card-front-overlay {\n  position: absolute;\n  inset: auto 0 0 0;\n  padding: 16px 18px;\n  background: linear-gradient(\n    180deg,\n    rgba(8, 5, 20, 0) 0%,\n    rgba(8, 5, 20, 0.72) 52%,\n    rgba(8, 5, 20, 0.88) 100%\n  );\n  pointer-events: none;\n}\n\n.flip-card-hint {\n  margin-top: 0;\n  font-size: 0.78em;\n  color: rgba(255, 255, 255, 0.82);\n  letter-spacing: 1px;\n  text-align: right;\n  text-transform: uppercase;\n}\n\n/* Back face */\n.flip-card-back {\n  background: linear-gradient(145deg, rgba(10, 5, 30, 0.98) 0%, rgba(25, 8, 55, 0.96) 100%);\n  border: 1px solid rgba(0, 212, 255, 0.3);\n  box-shadow: 0 8px 30px rgba(0, 100, 200, 0.3), inset 0 0 80px rgba(0, 212, 255, 0.03);\n  transform: rotateY(180deg);\n  display: flex;\n  flex-direction: column;\n  justify-content: center;\n  align-items: center;\n  padding: 32px 28px;\n  text-align: center;\n  gap: 16px;\n}\n\n.flip-back-glow {\n  position: absolute;\n  width: 200px;\n  height: 200px;\n  background: radial-gradient(circle, rgba(0, 212, 255, 0.12), transparent 70%);\n  border-radius: 50%;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%);\n  pointer-events: none;\n}\n\n.flip-back-title {\n  font-size: 1.35em;\n  font-weight: 700;\n  color: var(--cyan);\n  text-shadow: 0 0 15px rgba(0, 212, 255, 0.5);\n  margin: 0;\n}\n\n.flip-back-desc {\n  font-size: 0.9em;\n  color: rgba(255, 255, 255, 0.82);\n  line-height: 1.65;\n  margin: 0;\n  max-height: 150px;\n  overflow: auto;\n  padding-right: 4px;\n}\n\n.flip-back-buttons {\n  display: flex;\n  gap: 10px;\n  flex-wrap: wrap;\n  justify-content: center;\n}\n\n.flip-back-tech {\n  display: flex;\n  gap: 8px;\n  flex-wrap: wrap;\n  justify-content: center;\n  margin-top: 4px;\n}\n\n.flip-tag {\n  background: rgba(0, 212, 255, 0.12);\n  border: 1px solid rgba(0, 212, 255, 0.3);\n  color: var(--cyan);\n  font-size: 0.72em;\n  padding: 3px 10px;\n  border-radius: 20px;\n  letter-spacing: 0.5px;\n}\n\n/* Research card specific spacing */\n.flip-card-research .flip-back-desc {\n  max-height: 180px;\n}\n\n/* Mobile: keep tap-to-flip interaction */\n@media (max-width: 767px) {\n  .flip-card { min-height: 400px; }\n  .flip-card-inner {\n    min-height: 400px;\n  }\n  .flip-back-desc {\n    max-height: 165px;\n  }\n}\n\n/* ============================\n   Projects Section\n   ============================ */\n.project-section {\n  position: relative !important;\n  padding-top: 150px !important;\n  padding-bottom: 30px !important;\n  background-image: var(--section-background-color) !important;\n}\n\n.project-card {\n  padding-top: 50px !important;\n  padding-bottom: 50px !important;\n  padding-left: 25px !important;\n  padding-right: 25px !important;\n  height: auto !important;\n}\n\n.projects-row {\n  align-items: stretch;\n}\n\n.project-card-view {\n  box-shadow: 0 4px 8px 4px rgba(119, 53, 136, 0.4) !important;\n  color: white !important;\n  background: var(--card-bg) !important;\n  border: 1px solid rgba(200, 137, 230, 0.25) !important;\n  border-radius: 15px !important;\n  opacity: 1 !important;\n  transition: all 0.4s var(--transition-smooth) !important;\n  height: 100% !important;\n  overflow: hidden !important;\n}\n\n.project-card-view:hover {\n  transform: scale(1.02) translateY(-8px) !important;\n  box-shadow: 0 12px 35px 8px rgba(129, 72, 144, 0.5) !important;\n  border: 1px solid rgba(200, 137, 230, 0.55) !important;\n}\n\n.project-card-view .card-body { padding: 20px 25px !important; }\n.project-card-view .card-title { font-size: 1.3em !important; margin-bottom: 15px !important; }\n\n.card-img-top {\n  padding: 15px 15px 0 15px !important;\n  opacity: 0.92 !important;\n  border-radius: 12px !important;\n  transition: opacity 0.4s ease, transform 0.4s ease !important;\n}\n\n.project-card-view:hover .card-img-top {\n  opacity: 1 !important;\n  transform: scale(1.02) !important;\n}\n\n.project-heading {\n  color: white !important;\n  font-size: 2.3em !important;\n  font-weight: 500 !important;\n  padding-top: 10px !important;\n  position: relative !important;\n  display: inline-block !important;\n}\n\n.project-heading::after {\n  content: \"\";\n  position: absolute;\n  bottom: -6px;\n  left: 50%;\n  transform: translateX(-50%);\n  width: 0;\n  height: 3px;\n  background: linear-gradient(90deg, transparent, #c770f0, #00d4ff, transparent);\n  border-radius: 2px;\n  animation: headingLine 3s ease-in-out infinite alternate;\n}\n\n@keyframes headingLine {\n  from { width: 40px; }\n  to   { width: 120px; }\n}\n\n/* ============================\n   Buttons\n   ============================ */\n.btn-primary {\n  color: #fff !important;\n  background: linear-gradient(135deg, #7b4397 0%, #623686 100%) !important;\n  border: none !important;\n  padding: 10px 20px !important;\n  border-radius: 8px !important;\n  font-weight: 500 !important;\n  letter-spacing: 0.5px !important;\n  transition: all 0.3s ease !important;\n  box-shadow: 0 4px 15px rgba(98, 54, 134, 0.4) !important;\n  position: relative;\n  overflow: hidden;\n}\n\n.btn-primary::before {\n  content: \"\";\n  position: absolute;\n  top: 0;\n  left: -100%;\n  width: 100%;\n  height: 100%;\n  background: linear-gradient(90deg, transparent, rgba(255,255,255,0.12), transparent);\n  transition: left 0.4s ease;\n}\n\n.btn-primary:hover::before { left: 100%; }\n\n.btn-primary:hover {\n  color: #fff !important;\n  background: linear-gradient(135deg, #9d50bb 0%, #7b4397 100%) !important;\n  transform: translateY(-2px) !important;\n  box-shadow: 0 8px 25px rgba(157, 80, 187, 0.55) !important;\n}\n\n.btn-primary:active { transform: translateY(0) !important; }\n\n.btn:focus {\n  outline: none !important;\n  box-shadow: 0 0 0 3px rgba(199, 112, 240, 0.3) !important;\n}\n\n/* ============================\n   Certification Cards\n   ============================ */\n.cert-card-view {\n  box-shadow: 0 4px 5px 3px rgba(119, 53, 136, 0.459) !important;\n  color: white !important;\n  background: linear-gradient(135deg, rgba(30, 20, 50, 0.9) 0%, rgba(50, 30, 70, 0.8) 100%) !important;\n  border: 1px solid rgba(200, 137, 230, 0.3) !important;\n  border-radius: 15px !important;\n  transition: all 0.4s ease !important;\n  height: 100% !important;\n  min-height: 180px !important;\n  position: relative;\n  overflow: hidden;\n}\n\n.cert-card-view::before {\n  content: \"\";\n  position: absolute;\n  top: 0;\n  left: -100%;\n  width: 100%;\n  height: 2px;\n  background: linear-gradient(90deg, transparent, #c770f0, #00d4ff, transparent);\n  transition: left 0.5s ease;\n}\n\n.cert-card-view:hover::before { left: 100%; }\n\n.cert-card-view:hover {\n  transform: scale(1.03) translateY(-5px) !important;\n  box-shadow: 0 10px 30px 5px rgba(129, 72, 144, 0.55) !important;\n  border: 1px solid rgba(200, 137, 230, 0.6) !important;\n}\n\n.cert-card-body {\n  display: flex !important;\n  flex-direction: column !important;\n  align-items: center !important;\n  justify-content: center !important;\n  text-align: center !important;\n  padding: 25px 20px !important;\n}\n\n.cert-icon {\n  font-size: 3em !important;\n  color: #c770f0 !important;\n  margin-bottom: 15px !important;\n  filter: drop-shadow(0 0 12px rgba(199, 112, 240, 0.7)) !important;\n  transition: transform 0.3s ease;\n}\n\n.cert-card-view:hover .cert-icon { transform: rotate(10deg) scale(1.1); }\n\n.cert-title {\n  font-size: 1.1em !important;\n  margin-bottom: 20px !important;\n  line-height: 1.4 !important;\n}\n\n.cert-btn {\n  margin-top: auto !important;\n  padding: 8px 25px !important;\n  border-radius: 20px !important;\n  font-weight: 500 !important;\n  letter-spacing: 0.5px !important;\n}\n\n/* ============================\n   Blog/Research card\n   ============================ */\n.blog-card {\n  padding-top: 50px !important;\n  padding-bottom: 50px !important;\n  padding-left: 25px !important;\n  padding-right: 25px !important;\n  height: auto !important;\n}\n\n.blog-card-view {\n  background-color: transparent !important;\n  box-shadow: 0 3px 3px 2px rgba(145, 77, 161, 0.459) !important;\n  color: white !important;\n  transition: all 0.5s ease !important;\n  height: 100% !important;\n}\n\n.blog-link { color: white !important; text-decoration: none !important; }\n.blog-link:hover { cursor: pointer !important; }\n\n.blog-card-view:hover {\n  transform: scale(1.02) !important;\n  overflow: hidden !important;\n  box-shadow: 0 3px 3px 5px rgba(155, 88, 173, 0.65) !important;\n}\n\n.blog-img {\n  padding: 0 !important;\n  opacity: 0.8 !important;\n  border-radius: 0 !important;\n}\n\n/* ============================\n   About Section\n   ============================ */\n.about-section {\n  position: relative !important;\n  padding-top: 150px !important;\n  padding-bottom: 30px !important;\n  background-image: var(--section-background-color) !important;\n  color: white !important;\n}\n\n.quote-card-view {\n  border: 1px solid rgba(200, 137, 230, 0.2) !important;\n  border-radius: 18px !important;\n  color: white !important;\n  background: linear-gradient(135deg, rgba(20, 15, 35, 0.85) 0%, rgba(40, 25, 55, 0.75) 100%) !important;\n  box-shadow: 0 4px 20px rgba(119, 53, 136, 0.25) !important;\n  transition: all 0.35s ease !important;\n  backdrop-filter: blur(8px) !important;\n  -webkit-backdrop-filter: blur(8px) !important;\n  overflow: hidden;\n  position: relative;\n}\n\n.quote-card-view::after {\n  content: \"\";\n  position: absolute;\n  bottom: 0;\n  left: 0;\n  width: 0;\n  height: 2px;\n  background: linear-gradient(90deg, #c770f0, #00d4ff);\n  transition: width 0.5s ease;\n}\n\n.quote-card-view:hover::after { width: 100%; }\n\n.quote-card-view:hover {\n  border: 1px solid rgba(200, 137, 230, 0.45) !important;\n  box-shadow: 0 8px 30px rgba(119, 53, 136, 0.4) !important;\n  transform: translateY(-4px) !important;\n}\n\n.quote-card-view .card-body { padding: 25px 30px !important; }\n.quote-card-view blockquote p { line-height: 1.7 !important; font-size: 1.05em !important; }\n\n.about-activity {\n  list-style: none !important;\n  text-align: left !important;\n  padding-left: 1px !important;\n}\n\n@media (max-width: 767px) { .about-img { padding-top: 0 !important; } }\n\n/* ============================\n   Skills Section\n   ============================ */\n.tech-icons {\n  font-size: 4.5em !important;\n  margin: 15px !important;\n  padding: 10px !important;\n  opacity: 0.93 !important;\n  border: 1.7px solid rgba(200, 137, 230, 0.5) !important;\n  vertical-align: middle !important;\n  text-align: center !important;\n  border-radius: 10px !important;\n  display: table !important;\n  box-shadow: 4px 5px 4px 3px rgba(89, 4, 168, 0.137) !important;\n  overflow: hidden !important;\n  transition: all 0.35s var(--transition-smooth) !important;\n  color: white !important;\n  cursor: pointer;\n  position: relative;\n}\n\n@media (max-width: 767px) { .tech-icons { margin: 10px !important; } }\n\n.tech-icons:hover {\n  transform: scale(1.18) translateY(-6px) !important;\n  border: 2px solid rgba(199, 112, 240, 0.9) !important;\n  box-shadow: 0 8px 30px rgba(199, 112, 240, 0.4), 0 0 15px rgba(199, 112, 240, 0.25) !important;\n  background: rgba(199, 112, 240, 0.08) !important;\n}\n\n.tech-icon-label {\n  font-size: 0.25em !important;\n  margin-top: 8px !important;\n  margin-bottom: 0 !important;\n  color: #c770f0 !important;\n  font-weight: 500 !important;\n  text-transform: uppercase !important;\n  letter-spacing: 0.5px !important;\n}\n\n.tech-icon-images {\n  padding: 20px !important;\n  line-height: 1.6 !important;\n}\n\n/* ============================\n   Resume Section\n   ============================ */\n.resume-section {\n  position: relative !important;\n  padding-top: 110px !important;\n  padding-bottom: 30px !important;\n  background-image: var(--section-background-color) !important;\n  color: white !important;\n}\n\n.resume { padding-top: 50px; padding-bottom: 50px; justify-content: center; }\n.resume-left  { padding-right: 80px !important; }\n.resume-right { padding-left: 80px !important; }\n\n@media (max-width: 767px) {\n  .resume-left  { padding-right: 15px !important; padding-left: 15px !important; }\n  .resume-right { padding-right: 15px !important; padding-left: 15px !important; }\n}\n\n.resume .resume-title { font-size: 2em; font-weight: 700; padding-top: 30px; padding-bottom: 30px; }\n\n.resume .resume-item {\n  padding: 0 0 10px 25px;\n  margin-top: -2px;\n  border-left: 2px solid #8a49a8;\n  position: relative;\n}\n\n.resume .resume-item .resume-title {\n  line-height: 18px;\n  font-size: 0.9em;\n  background: #5234795d;\n  padding: 8px 15px;\n  display: inline-block;\n  font-weight: 600;\n  margin-bottom: 10px;\n}\n\n.resume .resume-item ul { padding-left: 20px; text-align: justify; }\n\n.resume .resume-item ul li { padding-bottom: 10px; list-style: none; }\n\n.resume .resume-item:last-child { padding-bottom: 0; }\n\n.resume .resume-item::before {\n  content: \"\";\n  position: absolute;\n  width: 16px;\n  height: 16px;\n  border-radius: 50px;\n  left: -9px;\n  top: 0;\n  background: #fff;\n  border: 2px solid #8a49a8;\n}\n\n.like-item { padding-top: 10px !important; font-size: 1.1em !important; font-family: sans-serif !important; }\n\n.like-btn {\n  background-color: #934cce5e !important;\n  border-color: #934cce5e !important;\n  padding: 0.25rem 0.98rem !important;\n  border-radius: 5px !important;\n  line-height: 1.4 !important;\n  transition: 0.3s ease !important;\n}\n\n.like-btn:hover {\n  transform: translateY(-2px) !important;\n  background-color: #a24dd386 !important;\n  border-color: #a24dd386 !important;\n}\n\n.animate-like {\n  animation-name: likeAnimation;\n  animation-fill-mode: forwards;\n  animation-duration: 0.85s;\n}\n\n@keyframes likeAnimation {\n  0%   { transform: scale(1.5); }\n  100% { transform: scale(1); }\n}\n\n.fork-btn { font-size: 1.1em !important; padding-top: 10px !important; }\n\n.fork-btn-inner {\n  line-height: 1.4em !important;\n  background-color: #934cce5e !important;\n  padding: 0.25rem 1.1rem !important;\n  vertical-align: middle !important;\n  text-align: center !important;\n}\n\n.fork-btn-inner:hover {\n  transform: translateY(-2px) !important;\n  background-color: #a24dd386 !important;\n  border-color: #a24dd386 !important;\n}\n\n.fork-btn-inner::after { display: none !important; }\n\n/* ============================\n   Footer\n   ============================ */\n.footer {\n  background: linear-gradient(to right, rgba(10, 4, 22, 0.98), rgba(15, 6, 35, 0.98));\n  border-top: 1px solid rgba(199, 112, 240, 0.1);\n  bottom: 0 !important;\n  padding-top: 10px !important;\n  padding-bottom: 8px !important;\n}\n\n.footer-copywright { text-align: center !important; }\n.footer-body { z-index: 1; text-align: center !important; }\n\n@media (max-width: 767px) {\n  .footer-copywright { text-align: center !important; }\n  .footer-body { text-align: center !important; }\n}\n\n.footer h3 { font-size: 1em; color: white !important; margin-top: 0.5em !important; margin-bottom: 0.5em !important; }\n.footer-icons { margin-top: 0.5em !important; margin-bottom: 0.5em !important; padding: 0 !important; }\n.blockquote-footer { color: #a588c0 !important; }\n\n/* ============================\n   Easter Egg\n   ============================ */\n.easter-egg-overlay {\n  position: fixed;\n  inset: 0;\n  background: rgba(5, 2, 18, 0.92);\n  z-index: 200000;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  cursor: pointer;\n  animation: eggFadeIn 0.3s ease;\n  backdrop-filter: blur(6px);\n}\n\n.easter-egg-content {\n  text-align: center;\n  color: white;\n  animation: eggPop 0.5s var(--transition-smooth);\n  padding: 20px;\n  max-width: 480px;\n}\n\n.easter-egg-emoji {\n  font-size: 5em;\n  animation: eggSpin 1s ease;\n  display: block;\n  margin-bottom: 16px;\n}\n\n.easter-egg-content h2 {\n  font-size: 2.2em;\n  font-weight: 800;\n  background: linear-gradient(135deg, #c770f0, #00d4ff, #ff006e);\n  background-size: 200% 100%;\n  -webkit-background-clip: text;\n  -webkit-text-fill-color: transparent;\n  background-clip: text;\n  animation: gradientShift 2s ease infinite;\n  margin: 0 0 12px;\n}\n\n.easter-egg-content p { font-size: 1.15em; color: rgba(255, 255, 255, 0.82); margin: 0; }\n\n.easter-egg-sparkles {\n  font-size: 2em;\n  margin-top: 20px;\n  animation: sparkleAnim 0.8s ease-in-out infinite alternate;\n  display: block;\n}\n\n.easter-egg-hint {\n  font-size: 0.8em !important;\n  color: rgba(199, 112, 240, 0.55) !important;\n  margin-top: 14px !important;\n  letter-spacing: 1px;\n}\n\n@keyframes eggFadeIn { from { opacity: 0; } to { opacity: 1; } }\n@keyframes eggPop { from { transform: scale(0.5); opacity: 0; } to { transform: scale(1); opacity: 1; } }\n@keyframes eggSpin { from { transform: rotate(0deg) scale(0); } to { transform: rotate(720deg) scale(1); } }\n@keyframes sparkleAnim { from { opacity: 0.4; transform: scale(0.9); } to { opacity: 1; transform: scale(1.1); } }\n\n/* ============================\n   About Image Float\n   ============================ */\n.about-float-img {\n  border-radius: 16px;\n  transition: transform 0.4s ease, filter 0.4s ease;\n  filter: drop-shadow(0 4px 20px rgba(199, 112, 240, 0.2));\n}\n\n.about-float-img:hover {\n  transform: scale(1.03) rotate(1deg);\n  filter: drop-shadow(0 8px 35px rgba(199, 112, 240, 0.45));\n}\n\n/* ============================\n   Heading highlight underline\n   (for skills section sub-headings)\n   ============================ */\n.skills-heading {\n  color: white !important;\n  font-size: 1.8em !important;\n  font-weight: 600 !important;\n  padding-top: 10px !important;\n  margin-bottom: 10px !important;\n  position: relative !important;\n  display: inline-block !important;\n}\n\n.skills-heading::after {\n  content: \"\";\n  position: absolute;\n  bottom: -4px;\n  left: 0;\n  width: 40px;\n  height: 2px;\n  background: linear-gradient(90deg, #c770f0, #00d4ff);\n  border-radius: 2px;\n  transition: width 0.4s ease;\n}\n\n.skills-heading:hover::after { width: 100%; }\n\n/* ============================\n   Particle z-index fix\n   ============================ */\n.home-section #tsparticles { z-index: 1; }\n.home-content { z-index: 2 !important; }\n\n/* ============================\n   Enhanced Preloader\n   ============================ */\n#preloader {\n  position: fixed;\n  top: 0;\n  left: 0;\n  width: 100%;\n  height: 100%;\n  z-index: 999999;\n  background: radial-gradient(ellipse at center, #1a0533 0%, #0c0513 60%, #050310 100%);\n  display: flex;\n  align-items: center;\n  justify-content: center;\n}\n\n#preloader-none {\n  opacity: 0;\n  pointer-events: none;\n  transition: opacity 0.4s ease;\n}\n\n.preloader-inner {\n  position: relative;\n  width: 120px;\n  height: 120px;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n}\n\n.preloader-ring {\n  position: absolute;\n  inset: 0;\n  border-radius: 50%;\n  border: 3px solid transparent;\n  border-top-color: #c770f0;\n  animation: preloaderSpin 1.1s linear infinite;\n}\n\n.preloader-ring-2 {\n  inset: 12px;\n  border-top-color: #00d4ff;\n  animation-duration: 0.85s;\n  animation-direction: reverse;\n}\n\n.preloader-ring-3 {\n  inset: 24px;\n  border-top-color: #ff006e;\n  animation-duration: 1.35s;\n}\n\n@keyframes preloaderSpin {\n  from { transform: rotate(0deg); }\n  to   { transform: rotate(360deg); }\n}\n\n.preloader-text {\n  font-size: 1.4em;\n  font-weight: 900;\n  background: linear-gradient(135deg, #c770f0, #00d4ff);\n  -webkit-background-clip: text;\n  -webkit-text-fill-color: transparent;\n  background-clip: text;\n  letter-spacing: 3px;\n  font-family: Georgia, serif;\n  animation: preloaderPulse 1.1s ease-in-out infinite alternate;\n}\n\n@keyframes preloaderPulse {\n  from { opacity: 0.6; }\n  to   { opacity: 1; }\n}\n\n/* ============================\n   Fun Fact Ticker / Marquee\n   ============================ */\n.ticker-wrapper {\n  display: flex;\n  align-items: center;\n  width: 100%;\n  overflow: hidden;\n  border-top: 1px solid rgba(199, 112, 240, 0.2);\n  border-bottom: 1px solid rgba(199, 112, 240, 0.2);\n  background: rgba(199, 112, 240, 0.04);\n  padding: 10px 0;\n  position: relative;\n  z-index: 2;\n  margin-top: 10px;\n}\n\n.ticker-label {\n  flex-shrink: 0;\n  color: var(--imp-text-color);\n  font-size: 0.7em;\n  font-weight: 700;\n  letter-spacing: 2px;\n  text-transform: uppercase;\n  padding: 0 18px;\n  border-right: 1px solid rgba(199, 112, 240, 0.3);\n  white-space: nowrap;\n}\n\n.ticker-track {\n  overflow: hidden;\n  flex: 1;\n}\n\n.ticker-inner {\n  display: flex;\n  white-space: nowrap;\n  animation: tickerScroll 55s linear infinite;\n}\n\n.ticker-inner:hover {\n  animation-play-state: paused;\n}\n\n@keyframes tickerScroll {\n  from { transform: translateX(0); }\n  to   { transform: translateX(-50%); }\n}\n\n.ticker-item {\n  display: inline-flex;\n  align-items: center;\n  font-size: 0.88em;\n  color: rgba(255, 255, 255, 0.75);\n  padding: 0 6px;\n}\n\n.ticker-sep {\n  color: var(--imp-text-color);\n  margin: 0 14px;\n  opacity: 0.5;\n  font-size: 0.7em;\n}\n\n@media (max-width: 767px) {\n  .ticker-label { display: none; }\n  .ticker-item { font-size: 0.8em; }\n}\n\n/* ============================\n   Back to Top Button\n   ============================ */\n.back-to-top {\n  position: fixed;\n  bottom: 32px;\n  right: 28px;\n  width: 46px;\n  height: 46px;\n  border-radius: 50%;\n  background: linear-gradient(135deg, #7b4397, #c770f0);\n  border: none;\n  color: white;\n  font-size: 1.2em;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  cursor: pointer;\n  z-index: 9999;\n  box-shadow: 0 4px 20px rgba(199, 112, 240, 0.45);\n  opacity: 0;\n  transform: translateY(20px) scale(0.8);\n  transition: opacity 0.3s ease, transform 0.3s ease, box-shadow 0.3s ease;\n  pointer-events: none;\n}\n\n.back-to-top.btt-visible {\n  opacity: 1;\n  transform: translateY(0) scale(1);\n  pointer-events: auto;\n}\n\n.back-to-top:hover {\n  box-shadow: 0 6px 30px rgba(199, 112, 240, 0.7);\n  transform: translateY(-3px) scale(1.08);\n}\n\n.back-to-top:active {\n  transform: translateY(0) scale(0.96);\n}\n\n@media (max-width: 767px) {\n  .back-to-top {\n    bottom: 20px;\n    right: 16px;\n    width: 42px;\n    height: 42px;\n  }\n}\n\n/* ============================\n   Active Nav Link\n   ============================ */\n.navbar-nav .nav-item .nav-link.nav-link-active {\n  color: var(--imp-text-color) !important;\n}\n\n.navbar-nav .nav-item .nav-link.nav-link-active::after {\n  width: 100% !important;\n}\n",".App {\r\n  text-align: center;\r\n}\r\n\r\n.App-logo {\r\n  height: 40vmin;\r\n  pointer-events: none;\r\n}\r\n\r\n@media (prefers-reduced-motion: no-preference) {\r\n  .App-logo {\r\n    animation: App-logo-spin infinite 20s linear;\r\n  }\r\n}\r\n\r\n.App-header {\r\n  background-color: #282c34;\r\n  min-height: 100vh;\r\n  display: flex;\r\n  flex-direction: column;\r\n  align-items: center;\r\n  justify-content: center;\r\n  font-size: calc(10px + 2vmin);\r\n  color: white;\r\n}\r\n\r\n.App-link {\r\n  color: #61dafb;\r\n}\r\n\r\n@keyframes App-logo-spin {\r\n  from {\r\n    transform: rotate(0deg);\r\n  }\r\n  to {\r\n    transform: rotate(360deg);\r\n  }\r\n}\r\n","@mixin bsBanner($file) {\n  /*!\n   * Bootstrap #{$file} v5.3.3 (https://getbootstrap.com/)\n   * Copyright 2011-2024 The Bootstrap Authors\n   * Licensed under MIT (https://github.com/twbs/bootstrap/blob/main/LICENSE)\n   */\n}\n",":root,\n[data-bs-theme=\"light\"] {\n  // Note: Custom variable values only support SassScript inside `#{}`.\n\n  // Colors\n  //\n  // Generate palettes for full colors, grays, and theme colors.\n\n  @each $color, $value in $colors {\n    --#{$prefix}#{$color}: #{$value};\n  }\n\n  @each $color, $value in $grays {\n    --#{$prefix}gray-#{$color}: #{$value};\n  }\n\n  @each $color, $value in $theme-colors {\n    --#{$prefix}#{$color}: #{$value};\n  }\n\n  @each $color, $value in $theme-colors-rgb {\n    --#{$prefix}#{$color}-rgb: #{$value};\n  }\n\n  @each $color, $value in $theme-colors-text {\n    --#{$prefix}#{$color}-text-emphasis: #{$value};\n  }\n\n  @each $color, $value in $theme-colors-bg-subtle {\n    --#{$prefix}#{$color}-bg-subtle: #{$value};\n  }\n\n  @each $color, $value in $theme-colors-border-subtle {\n    --#{$prefix}#{$color}-border-subtle: #{$value};\n  }\n\n  --#{$prefix}white-rgb: #{to-rgb($white)};\n  --#{$prefix}black-rgb: #{to-rgb($black)};\n\n  // Fonts\n\n  // Note: Use `inspect` for lists so that quoted items keep the quotes.\n  // See https://github.com/sass/sass/issues/2383#issuecomment-336349172\n  --#{$prefix}font-sans-serif: #{inspect($font-family-sans-serif)};\n  --#{$prefix}font-monospace: #{inspect($font-family-monospace)};\n  --#{$prefix}gradient: #{$gradient};\n\n  // Root and body\n  // scss-docs-start root-body-variables\n  @if $font-size-root != null {\n    --#{$prefix}root-font-size: #{$font-size-root};\n  }\n  --#{$prefix}body-font-family: #{inspect($font-family-base)};\n  @include rfs($font-size-base, --#{$prefix}body-font-size);\n  --#{$prefix}body-font-weight: #{$font-weight-base};\n  --#{$prefix}body-line-height: #{$line-height-base};\n  @if $body-text-align != null {\n    --#{$prefix}body-text-align: #{$body-text-align};\n  }\n\n  --#{$prefix}body-color: #{$body-color};\n  --#{$prefix}body-color-rgb: #{to-rgb($body-color)};\n  --#{$prefix}body-bg: #{$body-bg};\n  --#{$prefix}body-bg-rgb: #{to-rgb($body-bg)};\n\n  --#{$prefix}emphasis-color: #{$body-emphasis-color};\n  --#{$prefix}emphasis-color-rgb: #{to-rgb($body-emphasis-color)};\n\n  --#{$prefix}secondary-color: #{$body-secondary-color};\n  --#{$prefix}secondary-color-rgb: #{to-rgb($body-secondary-color)};\n  --#{$prefix}secondary-bg: #{$body-secondary-bg};\n  --#{$prefix}secondary-bg-rgb: #{to-rgb($body-secondary-bg)};\n\n  --#{$prefix}tertiary-color: #{$body-tertiary-color};\n  --#{$prefix}tertiary-color-rgb: #{to-rgb($body-tertiary-color)};\n  --#{$prefix}tertiary-bg: #{$body-tertiary-bg};\n  --#{$prefix}tertiary-bg-rgb: #{to-rgb($body-tertiary-bg)};\n  // scss-docs-end root-body-variables\n\n  --#{$prefix}heading-color: #{$headings-color};\n\n  --#{$prefix}link-color: #{$link-color};\n  --#{$prefix}link-color-rgb: #{to-rgb($link-color)};\n  --#{$prefix}link-decoration: #{$link-decoration};\n\n  --#{$prefix}link-hover-color: #{$link-hover-color};\n  --#{$prefix}link-hover-color-rgb: #{to-rgb($link-hover-color)};\n\n  @if $link-hover-decoration != null {\n    --#{$prefix}link-hover-decoration: #{$link-hover-decoration};\n  }\n\n  --#{$prefix}code-color: #{$code-color};\n  --#{$prefix}highlight-color: #{$mark-color};\n  --#{$prefix}highlight-bg: #{$mark-bg};\n\n  // scss-docs-start root-border-var\n  --#{$prefix}border-width: #{$border-width};\n  --#{$prefix}border-style: #{$border-style};\n  --#{$prefix}border-color: #{$border-color};\n  --#{$prefix}border-color-translucent: #{$border-color-translucent};\n\n  --#{$prefix}border-radius: #{$border-radius};\n  --#{$prefix}border-radius-sm: #{$border-radius-sm};\n  --#{$prefix}border-radius-lg: #{$border-radius-lg};\n  --#{$prefix}border-radius-xl: #{$border-radius-xl};\n  --#{$prefix}border-radius-xxl: #{$border-radius-xxl};\n  --#{$prefix}border-radius-2xl: var(--#{$prefix}border-radius-xxl); // Deprecated in v5.3.0 for consistency\n  --#{$prefix}border-radius-pill: #{$border-radius-pill};\n  // scss-docs-end root-border-var\n\n  --#{$prefix}box-shadow: #{$box-shadow};\n  --#{$prefix}box-shadow-sm: #{$box-shadow-sm};\n  --#{$prefix}box-shadow-lg: #{$box-shadow-lg};\n  --#{$prefix}box-shadow-inset: #{$box-shadow-inset};\n\n  // Focus styles\n  // scss-docs-start root-focus-variables\n  --#{$prefix}focus-ring-width: #{$focus-ring-width};\n  --#{$prefix}focus-ring-opacity: #{$focus-ring-opacity};\n  --#{$prefix}focus-ring-color: #{$focus-ring-color};\n  // scss-docs-end root-focus-variables\n\n  // scss-docs-start root-form-validation-variables\n  --#{$prefix}form-valid-color: #{$form-valid-color};\n  --#{$prefix}form-valid-border-color: #{$form-valid-border-color};\n  --#{$prefix}form-invalid-color: #{$form-invalid-color};\n  --#{$prefix}form-invalid-border-color: #{$form-invalid-border-color};\n  // scss-docs-end root-form-validation-variables\n}\n\n@if $enable-dark-mode {\n  @include color-mode(dark, true) {\n    color-scheme: dark;\n\n    // scss-docs-start root-dark-mode-vars\n    --#{$prefix}body-color: #{$body-color-dark};\n    --#{$prefix}body-color-rgb: #{to-rgb($body-color-dark)};\n    --#{$prefix}body-bg: #{$body-bg-dark};\n    --#{$prefix}body-bg-rgb: #{to-rgb($body-bg-dark)};\n\n    --#{$prefix}emphasis-color: #{$body-emphasis-color-dark};\n    --#{$prefix}emphasis-color-rgb: #{to-rgb($body-emphasis-color-dark)};\n\n    --#{$prefix}secondary-color: #{$body-secondary-color-dark};\n    --#{$prefix}secondary-color-rgb: #{to-rgb($body-secondary-color-dark)};\n    --#{$prefix}secondary-bg: #{$body-secondary-bg-dark};\n    --#{$prefix}secondary-bg-rgb: #{to-rgb($body-secondary-bg-dark)};\n\n    --#{$prefix}tertiary-color: #{$body-tertiary-color-dark};\n    --#{$prefix}tertiary-color-rgb: #{to-rgb($body-tertiary-color-dark)};\n    --#{$prefix}tertiary-bg: #{$body-tertiary-bg-dark};\n    --#{$prefix}tertiary-bg-rgb: #{to-rgb($body-tertiary-bg-dark)};\n\n    @each $color, $value in $theme-colors-text-dark {\n      --#{$prefix}#{$color}-text-emphasis: #{$value};\n    }\n\n    @each $color, $value in $theme-colors-bg-subtle-dark {\n      --#{$prefix}#{$color}-bg-subtle: #{$value};\n    }\n\n    @each $color, $value in $theme-colors-border-subtle-dark {\n      --#{$prefix}#{$color}-border-subtle: #{$value};\n    }\n\n    --#{$prefix}heading-color: #{$headings-color-dark};\n\n    --#{$prefix}link-color: #{$link-color-dark};\n    --#{$prefix}link-hover-color: #{$link-hover-color-dark};\n    --#{$prefix}link-color-rgb: #{to-rgb($link-color-dark)};\n    --#{$prefix}link-hover-color-rgb: #{to-rgb($link-hover-color-dark)};\n\n    --#{$prefix}code-color: #{$code-color-dark};\n    --#{$prefix}highlight-color: #{$mark-color-dark};\n    --#{$prefix}highlight-bg: #{$mark-bg-dark};\n\n    --#{$prefix}border-color: #{$border-color-dark};\n    --#{$prefix}border-color-translucent: #{$border-color-translucent-dark};\n\n    --#{$prefix}form-valid-color: #{$form-valid-color-dark};\n    --#{$prefix}form-valid-border-color: #{$form-valid-border-color-dark};\n    --#{$prefix}form-invalid-color: #{$form-invalid-color-dark};\n    --#{$prefix}form-invalid-border-color: #{$form-invalid-border-color-dark};\n    // scss-docs-end root-dark-mode-vars\n  }\n}\n","// stylelint-disable scss/dimension-no-non-numeric-values\n\n// SCSS RFS mixin\n//\n// Automated responsive values for font sizes, paddings, margins and much more\n//\n// Licensed under MIT (https://github.com/twbs/rfs/blob/main/LICENSE)\n\n// Configuration\n\n// Base value\n$rfs-base-value: 1.25rem !default;\n$rfs-unit: rem !default;\n\n@if $rfs-unit != rem and $rfs-unit != px {\n  @error \"`#{$rfs-unit}` is not a valid unit for $rfs-unit. Use `px` or `rem`.\";\n}\n\n// Breakpoint at where values start decreasing if screen width is smaller\n$rfs-breakpoint: 1200px !default;\n$rfs-breakpoint-unit: px !default;\n\n@if $rfs-breakpoint-unit != px and $rfs-breakpoint-unit != em and $rfs-breakpoint-unit != rem {\n  @error \"`#{$rfs-breakpoint-unit}` is not a valid unit for $rfs-breakpoint-unit. Use `px`, `em` or `rem`.\";\n}\n\n// Resize values based on screen height and width\n$rfs-two-dimensional: false !default;\n\n// Factor of decrease\n$rfs-factor: 10 !default;\n\n@if type-of($rfs-factor) != number or $rfs-factor <= 1 {\n  @error \"`#{$rfs-factor}` is not a valid  $rfs-factor, it must be greater than 1.\";\n}\n\n// Mode. Possibilities: \"min-media-query\", \"max-media-query\"\n$rfs-mode: min-media-query !default;\n\n// Generate enable or disable classes. Possibilities: false, \"enable\" or \"disable\"\n$rfs-class: false !default;\n\n// 1 rem = $rfs-rem-value px\n$rfs-rem-value: 16 !default;\n\n// Safari iframe resize bug: https://github.com/twbs/rfs/issues/14\n$rfs-safari-iframe-resize-bug-fix: false !default;\n\n// Disable RFS by setting $enable-rfs to false\n$enable-rfs: true !default;\n\n// Cache $rfs-base-value unit\n$rfs-base-value-unit: unit($rfs-base-value);\n\n@function divide($dividend, $divisor, $precision: 10) {\n  $sign: if($dividend > 0 and $divisor > 0 or $dividend < 0 and $divisor < 0, 1, -1);\n  $dividend: abs($dividend);\n  $divisor: abs($divisor);\n  @if $dividend == 0 {\n    @return 0;\n  }\n  @if $divisor == 0 {\n    @error \"Cannot divide by 0\";\n  }\n  $remainder: $dividend;\n  $result: 0;\n  $factor: 10;\n  @while ($remainder > 0 and $precision >= 0) {\n    $quotient: 0;\n    @while ($remainder >= $divisor) {\n      $remainder: $remainder - $divisor;\n      $quotient: $quotient + 1;\n    }\n    $result: $result * 10 + $quotient;\n    $factor: $factor * .1;\n    $remainder: $remainder * 10;\n    $precision: $precision - 1;\n    @if ($precision < 0 and $remainder >= $divisor * 5) {\n      $result: $result + 1;\n    }\n  }\n  $result: $result * $factor * $sign;\n  $dividend-unit: unit($dividend);\n  $divisor-unit: unit($divisor);\n  $unit-map: (\n    \"px\": 1px,\n    \"rem\": 1rem,\n    \"em\": 1em,\n    \"%\": 1%\n  );\n  @if ($dividend-unit != $divisor-unit and map-has-key($unit-map, $dividend-unit)) {\n    $result: $result * map-get($unit-map, $dividend-unit);\n  }\n  @return $result;\n}\n\n// Remove px-unit from $rfs-base-value for calculations\n@if $rfs-base-value-unit == px {\n  $rfs-base-value: divide($rfs-base-value, $rfs-base-value * 0 + 1);\n}\n@else if $rfs-base-value-unit == rem {\n  $rfs-base-value: divide($rfs-base-value, divide($rfs-base-value * 0 + 1, $rfs-rem-value));\n}\n\n// Cache $rfs-breakpoint unit to prevent multiple calls\n$rfs-breakpoint-unit-cache: unit($rfs-breakpoint);\n\n// Remove unit from $rfs-breakpoint for calculations\n@if $rfs-breakpoint-unit-cache == px {\n  $rfs-breakpoint: divide($rfs-breakpoint, $rfs-breakpoint * 0 + 1);\n}\n@else if $rfs-breakpoint-unit-cache == rem or $rfs-breakpoint-unit-cache == \"em\" {\n  $rfs-breakpoint: divide($rfs-breakpoint, divide($rfs-breakpoint * 0 + 1, $rfs-rem-value));\n}\n\n// Calculate the media query value\n$rfs-mq-value: if($rfs-breakpoint-unit == px, #{$rfs-breakpoint}px, #{divide($rfs-breakpoint, $rfs-rem-value)}#{$rfs-breakpoint-unit});\n$rfs-mq-property-width: if($rfs-mode == max-media-query, max-width, min-width);\n$rfs-mq-property-height: if($rfs-mode == max-media-query, max-height, min-height);\n\n// Internal mixin used to determine which media query needs to be used\n@mixin _rfs-media-query {\n  @if $rfs-two-dimensional {\n    @if $rfs-mode == max-media-query {\n      @media (#{$rfs-mq-property-width}: #{$rfs-mq-value}), (#{$rfs-mq-property-height}: #{$rfs-mq-value}) {\n        @content;\n      }\n    }\n    @else {\n      @media (#{$rfs-mq-property-width}: #{$rfs-mq-value}) and (#{$rfs-mq-property-height}: #{$rfs-mq-value}) {\n        @content;\n      }\n    }\n  }\n  @else {\n    @media (#{$rfs-mq-property-width}: #{$rfs-mq-value}) {\n      @content;\n    }\n  }\n}\n\n// Internal mixin that adds disable classes to the selector if needed.\n@mixin _rfs-rule {\n  @if $rfs-class == disable and $rfs-mode == max-media-query {\n    // Adding an extra class increases specificity, which prevents the media query to override the property\n    &,\n    .disable-rfs &,\n    &.disable-rfs {\n      @content;\n    }\n  }\n  @else if $rfs-class == enable and $rfs-mode == min-media-query {\n    .enable-rfs &,\n    &.enable-rfs {\n      @content;\n    }\n  } @else {\n    @content;\n  }\n}\n\n// Internal mixin that adds enable classes to the selector if needed.\n@mixin _rfs-media-query-rule {\n\n  @if $rfs-class == enable {\n    @if $rfs-mode == min-media-query {\n      @content;\n    }\n\n    @include _rfs-media-query () {\n      .enable-rfs &,\n      &.enable-rfs {\n        @content;\n      }\n    }\n  }\n  @else {\n    @if $rfs-class == disable and $rfs-mode == min-media-query {\n      .disable-rfs &,\n      &.disable-rfs {\n        @content;\n      }\n    }\n    @include _rfs-media-query () {\n      @content;\n    }\n  }\n}\n\n// Helper function to get the formatted non-responsive value\n@function rfs-value($values) {\n  // Convert to list\n  $values: if(type-of($values) != list, ($values,), $values);\n\n  $val: \"\";\n\n  // Loop over each value and calculate value\n  @each $value in $values {\n    @if $value == 0 {\n      $val: $val + \" 0\";\n    }\n    @else {\n      // Cache $value unit\n      $unit: if(type-of($value) == \"number\", unit($value), false);\n\n      @if $unit == px {\n        // Convert to rem if needed\n        $val: $val + \" \" + if($rfs-unit == rem, #{divide($value, $value * 0 + $rfs-rem-value)}rem, $value);\n      }\n      @else if $unit == rem {\n        // Convert to px if needed\n        $val: $val + \" \" + if($rfs-unit == px, #{divide($value, $value * 0 + 1) * $rfs-rem-value}px, $value);\n      } @else {\n        // If $value isn't a number (like inherit) or $value has a unit (not px or rem, like 1.5em) or $ is 0, just print the value\n        $val: $val + \" \" + $value;\n      }\n    }\n  }\n\n  // Remove first space\n  @return unquote(str-slice($val, 2));\n}\n\n// Helper function to get the responsive value calculated by RFS\n@function rfs-fluid-value($values) {\n  // Convert to list\n  $values: if(type-of($values) != list, ($values,), $values);\n\n  $val: \"\";\n\n  // Loop over each value and calculate value\n  @each $value in $values {\n    @if $value == 0 {\n      $val: $val + \" 0\";\n    } @else {\n      // Cache $value unit\n      $unit: if(type-of($value) == \"number\", unit($value), false);\n\n      // If $value isn't a number (like inherit) or $value has a unit (not px or rem, like 1.5em) or $ is 0, just print the value\n      @if not $unit or $unit != px and $unit != rem {\n        $val: $val + \" \" + $value;\n      } @else {\n        // Remove unit from $value for calculations\n        $value: divide($value, $value * 0 + if($unit == px, 1, divide(1, $rfs-rem-value)));\n\n        // Only add the media query if the value is greater than the minimum value\n        @if abs($value) <= $rfs-base-value or not $enable-rfs {\n          $val: $val + \" \" + if($rfs-unit == rem, #{divide($value, $rfs-rem-value)}rem, #{$value}px);\n        }\n        @else {\n          // Calculate the minimum value\n          $value-min: $rfs-base-value + divide(abs($value) - $rfs-base-value, $rfs-factor);\n\n          // Calculate difference between $value and the minimum value\n          $value-diff: abs($value) - $value-min;\n\n          // Base value formatting\n          $min-width: if($rfs-unit == rem, #{divide($value-min, $rfs-rem-value)}rem, #{$value-min}px);\n\n          // Use negative value if needed\n          $min-width: if($value < 0, -$min-width, $min-width);\n\n          // Use `vmin` if two-dimensional is enabled\n          $variable-unit: if($rfs-two-dimensional, vmin, vw);\n\n          // Calculate the variable width between 0 and $rfs-breakpoint\n          $variable-width: #{divide($value-diff * 100, $rfs-breakpoint)}#{$variable-unit};\n\n          // Return the calculated value\n          $val: $val + \" calc(\" + $min-width + if($value < 0, \" - \", \" + \") + $variable-width + \")\";\n        }\n      }\n    }\n  }\n\n  // Remove first space\n  @return unquote(str-slice($val, 2));\n}\n\n// RFS mixin\n@mixin rfs($values, $property: font-size) {\n  @if $values != null {\n    $val: rfs-value($values);\n    $fluid-val: rfs-fluid-value($values);\n\n    // Do not print the media query if responsive & non-responsive values are the same\n    @if $val == $fluid-val {\n      #{$property}: $val;\n    }\n    @else {\n      @include _rfs-rule () {\n        #{$property}: if($rfs-mode == max-media-query, $val, $fluid-val);\n\n        // Include safari iframe resize fix if needed\n        min-width: if($rfs-safari-iframe-resize-bug-fix, (0 * 1vw), null);\n      }\n\n      @include _rfs-media-query-rule () {\n        #{$property}: if($rfs-mode == max-media-query, $fluid-val, $val);\n      }\n    }\n  }\n}\n\n// Shorthand helper mixins\n@mixin font-size($value) {\n  @include rfs($value);\n}\n\n@mixin padding($value) {\n  @include rfs($value, padding);\n}\n\n@mixin padding-top($value) {\n  @include rfs($value, padding-top);\n}\n\n@mixin padding-right($value) {\n  @include rfs($value, padding-right);\n}\n\n@mixin padding-bottom($value) {\n  @include rfs($value, padding-bottom);\n}\n\n@mixin padding-left($value) {\n  @include rfs($value, padding-left);\n}\n\n@mixin margin($value) {\n  @include rfs($value, margin);\n}\n\n@mixin margin-top($value) {\n  @include rfs($value, margin-top);\n}\n\n@mixin margin-right($value) {\n  @include rfs($value, margin-right);\n}\n\n@mixin margin-bottom($value) {\n  @include rfs($value, margin-bottom);\n}\n\n@mixin margin-left($value) {\n  @include rfs($value, margin-left);\n}\n","// scss-docs-start color-mode-mixin\n@mixin color-mode($mode: light, $root: false) {\n  @if $color-mode-type == \"media-query\" {\n    @if $root == true {\n      @media (prefers-color-scheme: $mode) {\n        :root {\n          @content;\n        }\n      }\n    } @else {\n      @media 